UPDATE "h_dashboard_widget"
SET is_active = #{isActive},
    updated_at = now()
WHERE username = #{username}
  AND widget_key = #{widgetKey}
  AND (has_data = true OR #{isActive} = false)

UPDATE "h_dashboard_widget"
SET sort_order = #{sortOrder},
    updated_at = now()
WHERE username = #{username}
  AND widget_key = #{widgetKey}

UPDATE "h_dashboard_widget"
SET has_data = #{hasData},
    is_active = #{isActive},
    updated_at = now()
WHERE username = #{username}
  AND widget_key = #{widgetKey}

mapper.select:
SELECT to_char(p.pay_date, 'YYYY-MM') as "month", sum(p.pay_price) as "total" FROM "h_payment" p WHERE p.pay_date >= date_trunc('month', current_date) - interval '5 months'
AND p.gym_id = #{gymId}
GROUP BY to_char(p.pay_date, 'YYYY-MM') ORDER BY "month" ASC

SELECT to_char(e.expense_date, 'YYYY-MM') as "month", sum(e.expense_price) as "total" FROM "h_expense" e WHERE e.expense_date >= date_trunc('month', current_date) - interval '5 months'
AND e.gym_id = #{gymId}
GROUP BY to_char(e.expense_date, 'YYYY-MM') ORDER BY "month" ASC
